// // This module implements a 1-bit wide 2-to-1 demultiplexer. When S is high (1), F reflects the value of B; when S is low (0), F takes the value of A.
module top_module(A,B,S,F);input A, B, S;
	output reg F;

	always @(A,B,S) begin
		if(S == 1) begin
			F = A;
		end
		else	begin
			F = B;
		end
	end

endmodule
